async function execute(browser: WebFlowBrowserAPI, params: FlowParams): Promise<WebFlowResult> {
    const filterControl = await browser.extractComponent<{ label: string; cssSelector: string; type: string }>(
        {
            typeName: 'FilterControl',
            schema: '{ label: string; cssSelector: string; type: string; }'
        },
        params.filterCriteria
    );
    if (!filterControl || !filterControl.cssSelector) {
        throw new Error('Could not find filter for: ' + params.filterCriteria);
    }
    await browser.click(filterControl.cssSelector);
    await browser.awaitPageInteraction();
    return { success: true, message: 'Applied filter: ' + params.filterCriteria };
}
